const express = require('express');
const bodyParser = require('body-parser');
const helmet = require('helmet');
const jwt = require('jsonwebtoken');
const rateLimit = require('express-rate-limit');

const app = express();
app.use(bodyParser.json());
app.use(helmet());

const PORT = process.env.PORT || 3000;
const SECRET_KEY = process.env.SECRET_KEY || 'your-secure-secret-key';

// Rate limiter to prevent abuse
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100 // limit each IP to 100 requests per windowMs
});
app.use(limiter);

// Middleware to authenticate requests
function authenticateToken(req, res, next) {
  const token = req.headers['authorization'];
  if (!token) return res.sendStatus(401);

  jwt.verify(token, SECRET_KEY, (err, user) => {
    if (err) return res.sendStatus(403);
    req.user = user;
    next();
  });
}

// Validate level completion data
function validateLevelData(data) {
  const { levelId, score, time } = data;
  if (typeof levelId !== 'number' || typeof score !== 'number' || typeof time !== 'number') {
    return false;
  }
  return true;
}

// Endpoint to complete a level
app.post('/complete-level', authenticateToken, (req, res) => {
  const levelData = req.body;

  if (!validateLevelData(levelData)) {
    return res.status(400).json({ error: 'Invalid level data' });
  }

  // Process level completion and award rewards
  const { levelId, score, time } = levelData;
  const rewards = calculateRewards(score, time);

  // Log only necessary information
  console.log(`User ${req.user.id} completed level ${levelId} with score ${score} and time ${time}`);

  res.json({ message: 'Level completed', rewards });
});

// Calculate rewards based on score and time
function calculateRewards(score, time) {
  let rewards = 0;
  if (score > 1000) rewards += 10;
  if (time < 300) rewards += 5;
  return rewards;
}

// Endpoint to claim rewards
app.post('/claim-rewards', authenticateToken, (req, res) => {
  const { userId } = req.user;

  // Logic to claim rewards securely
  // Ensure rewards are not claimed multiple times
  console.log(`User ${userId} claimed rewards`);

  res.json({ message: 'Rewards claimed successfully' });
});

app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});